+/// Runtime monitor that checks observations against projected local session types.
+#[derive(Debug, Clone)]
+pub struct ConformanceMonitor {
+    contract_name: String,
+    roles: BTreeMap<RoleName, RoleConformanceState>,
+    history: Vec<ConformanceCheckRecord>,
+}
+
+impl ConformanceMonitor {
+    /// Build a fresh monitor from a validated protocol contract.
+    pub fn new(contract: &ProtocolContract) -> Result<Self, ConformanceMonitorInitError> {
+        Self::new_at(contract, Time::ZERO)
+    }
+
+    /// Build a fresh monitor with an explicit activation time.
+    pub fn new_at(
+        contract: &ProtocolContract,
+        start_time: Time,
+    ) -> Result<Self, ConformanceMonitorInitError> {
+        contract.validate()?;
+
+        let metadata = MonitorMetadata::from_contract(contract);
+        let mut roles = BTreeMap::new();
+        for role in &contract.roles {
+            let local = build_annotated_local_type(
+                &contract.global_type,
+                &contract.roles,
+                role,
+                &metadata,
+            )?;
+            roles.insert(role.clone(), RoleConformanceState::new(local, start_time));
+        }
+
+        Ok(Self {
+            contract_name: contract.name.clone(),
+            roles,
+            history: Vec::new(),
+        })
+    }
+
+    /// Return successful checks recorded so far.
+    #[must_use]
+    pub fn history(&self) -> &[ConformanceCheckRecord] {
+        &self.history
+    }
+
+    /// Return the current expectation for one role, when the role exists.
+    #[must_use]
+    pub fn pending_expectation(&self, role: &RoleName) -> Option<ConformanceExpectation> {
+        self.roles
+            .get(role)
+            .map(|state| state.current.expectation())
+    }
+
+    /// Return whether one role has reached protocol completion.
+    #[must_use]
+    pub fn is_role_complete(&self, role: &RoleName) -> bool {
+        self.roles
+            .get(role)
+            .is_some_and(RoleConformanceState::is_complete)
+    }
+
+    /// Return whether all roles have reached protocol completion.
+    #[must_use]
+    pub fn is_complete(&self) -> bool {
+        self.roles.values().all(RoleConformanceState::is_complete)
+    }
+
+    /// Observe one role-local transition without attaching a timestamp.
+    pub fn observe(
+        &mut self,
+        role: &RoleName,
+        message: Option<&MessageType>,
+        label: Option<&Label>,
+    ) -> Result<ConformanceCheckRecord, ConformanceViolation> {
+        self.observe_at_inner(role, message, label, None)
+    }
+
+    /// Observe one role-local transition at a specific logical time.
+    pub fn observe_at(
+        &mut self,
+        role: &RoleName,
+        message: Option<&MessageType>,
+        label: Option<&Label>,
+        now: Time,
+    ) -> Result<ConformanceCheckRecord, ConformanceViolation> {
+        self.observe_at_inner(role, message, label, Some(now))
+    }
+
+    /// Observe one role-local transition using `Cx` time/logging facilities.
+    pub fn observe_with_cx(
+        &mut self,
+        cx: &Cx,
+        role: &RoleName,
+        message: Option<&MessageType>,
+        label: Option<&Label>,
+    ) -> Result<ConformanceCheckRecord, ConformanceViolation> {
+        let now = cx.now();
+        match self.observe_at(role, message, label, now) {
+            Ok(record) => {
+                trace_conformance_check(
+                    cx,
+                    &self.contract_name,
+                    &record.role,
+                    &record.path,
+                    "ok",
+                    &record.observed,
+                );
+                Ok(record)
+            }
+            Err(violation) => {
+                let path = violation_path(&violation);
+                trace_conformance_check(
+                    cx,
+                    &self.contract_name,
+                    role,
+                    path.as_ref().unwrap_or(&SessionPath::root()),
+                    "violation",
+                    &ConformanceObserved::from_inputs(message, label),
+                );
+                Err(violation)
+            }
+        }
+    }
+
+    /// Check whether any role timed out by `now`.
+    pub fn check_timeout(&self, now: Time) -> Result<(), ConformanceViolation> {
+        for (role, state) in &self.roles {
+            if state.is_complete() {
+                continue;
+            }
+            let Some(timeout) = state.current.timeout_budget() else {
+                continue;
+            };
+            let elapsed_nanos = now.duration_since(state.entered_at);
+            let timeout_nanos = duration_to_nanos(timeout);
+            if elapsed_nanos > timeout_nanos {
+                return Err(ConformanceViolation::Timeout {
+                    contract_name: self.contract_name.clone(),
+                    role: role.clone(),
+                    expected: state.current.expectation(),
+                    elapsed: Duration::from_nanos(elapsed_nanos),
+                    evidence: state.current.violation_evidence(&self.contract_name, role),
+                });
+            }
+        }
+        Ok(())
+    }
+
+    fn observe_at_inner(
+        &mut self,
+        role: &RoleName,
+        message: Option<&MessageType>,
+        label: Option<&Label>,
+        now: Option<Time>,
+    ) -> Result<ConformanceCheckRecord, ConformanceViolation> {
+        let contract_name = self.contract_name.clone();
+        let observed = ConformanceObserved::from_inputs(message, label);
+        let role_state =
+            self.roles
+                .get_mut(role)
+                .ok_or_else(|| ConformanceViolation::UnknownRole {
+                    contract_name: contract_name.clone(),
+                    role: role.clone(),
+                })?;
+
+        if role_state.is_complete() {
+            return Err(ConformanceViolation::AlreadyComplete {
+                contract_name,
+                role: role.clone(),
+                observed,
+            });
+        }
+
+        if let Some(now) = now {
+            if let Some(timeout) = role_state.current.timeout_budget() {
+                let elapsed_nanos = now.duration_since(role_state.entered_at);
+                let timeout_nanos = duration_to_nanos(timeout);
+                if elapsed_nanos > timeout_nanos {
+                    return Err(ConformanceViolation::Timeout {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected: role_state.current.expectation(),
+                        elapsed: Duration::from_nanos(elapsed_nanos),
+                        evidence: role_state.current.violation_evidence(&contract_name, role),
+                    });
+                }
+            }
+        }
+
+        let record = match role_state.current.clone() {
+            AnnotatedLocalType::Send {
+                path,
+                metadata,
+                message: expected_message,
+                next,
+            } => {
+                if label.is_some() || message != Some(&expected_message) {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected: ConformanceExpectation::Send {
+                            message: expected_message,
+                        },
+                        observed,
+                        evidence: metadata.to_violation_evidence(&contract_name, role, path),
+                    });
+                }
+                let record = ConformanceCheckRecord {
+                    role: role.clone(),
+                    path,
+                    expectation: ConformanceExpectation::Send {
+                        message: expected_message,
+                    },
+                    observed,
+                    observed_at: now,
+                    evidence_checkpoints: metadata.evidence_checkpoints.clone(),
+                    timeout: metadata.timeout,
+                    compensation_paths: metadata.compensation_paths.clone(),
+                    cutoff_paths: metadata.cutoff_paths.clone(),
+                };
+                role_state.advance_to(*next, now.unwrap_or(role_state.entered_at));
+                record
+            }
+            AnnotatedLocalType::Receive {
+                path,
+                metadata,
+                message: expected_message,
+                next,
+            } => {
+                if label.is_some() || message != Some(&expected_message) {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected: ConformanceExpectation::Receive {
+                            message: expected_message,
+                        },
+                        observed,
+                        evidence: metadata.to_violation_evidence(&contract_name, role, path),
+                    });
+                }
+                let record = ConformanceCheckRecord {
+                    role: role.clone(),
+                    path,
+                    expectation: ConformanceExpectation::Receive {
+                        message: expected_message,
+                    },
+                    observed,
+                    observed_at: now,
+                    evidence_checkpoints: metadata.evidence_checkpoints.clone(),
+                    timeout: metadata.timeout,
+                    compensation_paths: metadata.compensation_paths.clone(),
+                    cutoff_paths: metadata.cutoff_paths.clone(),
+                };
+                role_state.advance_to(*next, now.unwrap_or(role_state.entered_at));
+                record
+            }
+            AnnotatedLocalType::Choice { branches } => {
+                let expected = ConformanceExpectation::ChooseBranch {
+                    labels: branches.iter().map(|branch| branch.label.clone()).collect(),
+                };
+                let Some(observed_label) = label else {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected,
+                        observed,
+                        evidence: aggregate_branch_evidence(&contract_name, role, &branches),
+                    });
+                };
+                if message.is_some() {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected,
+                        observed,
+                        evidence: aggregate_branch_evidence(&contract_name, role, &branches),
+                    });
+                }
+                let Some(branch) = branches
+                    .iter()
+                    .find(|branch| &branch.label == observed_label)
+                    .cloned()
+                else {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected,
+                        observed,
+                        evidence: aggregate_branch_evidence(&contract_name, role, &branches),
+                    });
+                };
+                let record = ConformanceCheckRecord {
+                    role: role.clone(),
+                    path: branch.path.clone(),
+                    expectation: ConformanceExpectation::ChooseBranch {
+                        labels: branches
+                            .iter()
+                            .map(|candidate| candidate.label.clone())
+                            .collect(),
+                    },
+                    observed,
+                    observed_at: now,
+                    evidence_checkpoints: branch.metadata.evidence_checkpoints.clone(),
+                    timeout: branch.metadata.timeout,
+                    compensation_paths: branch.metadata.compensation_paths.clone(),
+                    cutoff_paths: branch.metadata.cutoff_paths.clone(),
+                };
+                role_state.advance_to(branch.continuation, now.unwrap_or(role_state.entered_at));
+                record
+            }
+            AnnotatedLocalType::Branch { branches } => {
+                let expected = ConformanceExpectation::ObserveBranch {
+                    labels: branches.iter().map(|branch| branch.label.clone()).collect(),
+                };
+                let Some(observed_label) = label else {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected,
+                        observed,
+                        evidence: aggregate_branch_evidence(&contract_name, role, &branches),
+                    });
+                };
+                if message.is_some() {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected,
+                        observed,
+                        evidence: aggregate_branch_evidence(&contract_name, role, &branches),
+                    });
+                }
+                let Some(branch) = branches
+                    .iter()
+                    .find(|branch| &branch.label == observed_label)
+                    .cloned()
+                else {
+                    return Err(ConformanceViolation::UnexpectedObservation {
+                        contract_name: contract_name.clone(),
+                        role: role.clone(),
+                        expected,
+                        observed,
+                        evidence: aggregate_branch_evidence(&contract_name, role, &branches),
+                    });
+                };
+                let record = ConformanceCheckRecord {
+                    role: role.clone(),
+                    path: branch.path.clone(),
+                    expectation: ConformanceExpectation::ObserveBranch {
+                        labels: branches
+                            .iter()
+                            .map(|candidate| candidate.label.clone())
+                            .collect(),
+                    },
+                    observed,
+                    observed_at: now,
+                    evidence_checkpoints: branch.metadata.evidence_checkpoints.clone(),
+                    timeout: branch.metadata.timeout,
+                    compensation_paths: branch.metadata.compensation_paths.clone(),
+                    cutoff_paths: branch.metadata.cutoff_paths.clone(),
+                };
+                role_state.advance_to(branch.continuation, now.unwrap_or(role_state.entered_at));
+                record
+            }
+            AnnotatedLocalType::End { .. }
+            | AnnotatedLocalType::Recurse { .. }
+            | AnnotatedLocalType::RecursePoint { .. } => {
+                unreachable!("role state is normalized before runtime observation")
+            }
+        };
+
+        self.history.push(record.clone());
+        Ok(record)
+    }
+}
